
package com.secretariapay.api.entity.core;

import jakarta.persistence.*;
import java.time.*;
import java.math.BigDecimal;
import java.util.UUID;

@Entity @Table(name="billing_rules")
public class BillingRule { @Id @GeneratedValue(strategy=GenerationType.UUID) private UUID id; @Column(name="institution_id") private UUID institutionId; @Column(name="rule_name",nullable=false,length=140) private String ruleName; @Column(name="charge_type",nullable=false,length=80) private String chargeType="PROPINA"; @Column(name="due_day",nullable=false) private Integer dueDay=10; @Column(name="grace_days",nullable=false) private Integer graceDays=0; @Column(name="fine_type",nullable=false,length=30) private String fineType="NONE"; @Column(name="fine_value",nullable=false,precision=14,scale=2) private BigDecimal fineValue=BigDecimal.ZERO; @Column(name="interest_type",nullable=false,length=30) private String interestType="NONE"; @Column(name="daily_interest_value",nullable=false,precision=14,scale=2) private BigDecimal dailyInterestValue=BigDecimal.ZERO; @Column(name="discount_type",nullable=false,length=30) private String discountType="NONE"; @Column(name="discount_value",nullable=false,precision=14,scale=2) private BigDecimal discountValue=BigDecimal.ZERO; @Column(nullable=false) private Boolean active=true; @Column(name="created_at",nullable=false) private LocalDateTime createdAt; @Column(name="updated_at",nullable=false) private LocalDateTime updatedAt; @PrePersist public void prePersist(){LocalDateTime n=LocalDateTime.now();createdAt=n;updatedAt=n;if(active==null)active=true;} @PreUpdate public void preUpdate(){updatedAt=LocalDateTime.now();} public UUID getId(){return id;} public UUID getInstitutionId(){return institutionId;} public BillingRule setInstitutionId(UUID v){institutionId=v;return this;} public String getRuleName(){return ruleName;} public BillingRule setRuleName(String v){ruleName=v;return this;} public String getChargeType(){return chargeType;} public BillingRule setChargeType(String v){chargeType=v;return this;} public Integer getDueDay(){return dueDay;} public BillingRule setDueDay(Integer v){dueDay=v;return this;} public Integer getGraceDays(){return graceDays;} public BillingRule setGraceDays(Integer v){graceDays=v;return this;} public String getFineType(){return fineType;} public BillingRule setFineType(String v){fineType=v;return this;} public BigDecimal getFineValue(){return fineValue;} public BillingRule setFineValue(BigDecimal v){fineValue=v;return this;} public String getInterestType(){return interestType;} public BillingRule setInterestType(String v){interestType=v;return this;} public BigDecimal getDailyInterestValue(){return dailyInterestValue;} public BillingRule setDailyInterestValue(BigDecimal v){dailyInterestValue=v;return this;} public String getDiscountType(){return discountType;} public BillingRule setDiscountType(String v){discountType=v;return this;} public BigDecimal getDiscountValue(){return discountValue;} public BillingRule setDiscountValue(BigDecimal v){discountValue=v;return this;} public Boolean getActive(){return active;} public BillingRule setActive(Boolean v){active=v;return this;} public LocalDateTime getCreatedAt(){return createdAt;} public LocalDateTime getUpdatedAt(){return updatedAt;} }
